{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się odróżniać <strong>Present Perfect</strong> od <strong>Past Simple</strong> na podstawie związku z teraźniejszością.",
    "rules": [
        {
            "label": "SKUTEK TERAZ",
            "color": "emerald",
            "text": "<strong>Present Perfect</strong> pokazuje skutek teraz, doświadczenie życiowe albo okres trwający do chwili obecnej:",
            "example": "I have lost my keys."
        },
        {
            "label": "ZAKOŃCZONA PRZESZŁOŚĆ",
            "color": "blue",
            "text": "<strong>Past Simple</strong> pokazuje zakończoną czynność w określonym momencie przeszłym:",
            "example": "I lost my keys yesterday."
        },
        {
            "label": "WYRAŻENIA CZASU",
            "color": "amber",
            "text": "Słowa takie jak <strong>yesterday, last year, ago</strong> wskazują na Past Simple, a <strong>ever, never, already, yet, just</strong> często idą z Present Perfect.",
            "example": "Have you ever been there? / I went there last year."
        }
    ]
}

{
    "title": "1. Szybkie porównanie",
    "intro": "Zobacz różnicę w znaczeniu i znacznikach czasu.",
    "items": [
        {
            "label": "Present Perfect",
            "title": "have / has + V3",
            "subtitle": "I have finished. / She has already left."
        },
        {
            "label": "Past Simple",
            "title": "V2 / did",
            "subtitle": "I finished yesterday. / Did she leave early?"
        },
        {
            "label": "Niezakończony okres",
            "title": "today / this week / in my life",
            "subtitle": "często Present Perfect"
        },
        {
            "label": "Zakończony czas",
            "title": "yesterday / in 2019 / last night / ago",
            "subtitle": "zwykle Past Simple"
        }
    ]
}

{
    "title": "2. Kiedy używać której formy",
    "sections": [
        {
            "label": "Present Perfect: skutek i doświadczenie",
            "color": "emerald",
            "description": "Ta forma łączy przeszłą czynność z <strong>obecnym skutkiem</strong> albo z doświadczeniem życiowym.",
            "examples": [
                {
                    "en": "I have lost my keys, so I cannot open the door.",
                    "ua": "Zgubiłem klucze, więc nie mogę otworzyć drzwi."
                },
                {
                    "en": "She has visited Rome three times.",
                    "ua": "Ona była w Rzymie trzy razy."
                },
                {
                    "en": "We have lived here for five years.",
                    "ua": "Mieszkamy tu od pięciu lat."
                }
            ]
        },
        {
            "label": "Past Simple: zakończony moment w przeszłości",
            "color": "blue",
            "description": "Gdy czas jest <strong>zakończony i nazwany</strong>, potrzebujesz Past Simple.",
            "examples": [
                {
                    "en": "I lost my keys yesterday.",
                    "ua": "Zgubiłem klucze wczoraj."
                },
                {
                    "en": "She visited Rome in 2022.",
                    "ua": "Odwiedziła Rzym w 2022 roku."
                },
                {
                    "en": "We lived there when I was a child.",
                    "ua": "Mieszkaliśmy tam, kiedy byłem dzieckiem."
                }
            ]
        },
        {
            "label": "Niezakończony czas vs zakończony czas",
            "color": "amber",
            "description": "<strong>Today / this week / this year</strong> mogą być jeszcze otwarte, a <strong>yesterday / last week</strong> są już zakończone.",
            "examples": [
                {
                    "en": "I have seen Anna twice this week.",
                    "ua": "Widziałem Annę dwa razy w tym tygodniu."
                },
                {
                    "en": "I saw Anna twice last week.",
                    "ua": "Widziałem Annę dwa razy w zeszłym tygodniu."
                },
                {
                    "en": "Have you eaten today?",
                    "ua": "Czy jadłeś już dzisiaj?"
                }
            ],
            "note": "Zapytaj siebie: czy ten okres jeszcze trwa, czy już się zakończył?"
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Present Perfect z yesterday.",
            "wrong": "I have seen him yesterday.",
            "right": "✅ <span class=\"font-mono\">I saw him yesterday.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Past Simple przy doświadczeniu życiowym.",
            "wrong": "Did you ever visit London?",
            "right": "✅ <span class=\"font-mono\">Have you ever visited London?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Past Simple z for / since, gdy sytuacja trwa do teraz.",
            "wrong": "We lived here for five years. <span class=\"text-slate-500\">(and still live here)</span>",
            "right": "✅ <span class=\"font-mono\">We have lived here for five years.</span>"
        }
    ]
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "<strong>Present Perfect</strong> = związek z teraźniejszością, skutek teraz, doświadczenie, okres do teraz.",
        "<strong>Past Simple</strong> = zakończony moment albo zakończony okres w przeszłości.",
        "<strong>Yesterday, last, ago, in 2020</strong> prawie zawsze prowadzą do Past Simple.",
        "<strong>Ever, never, already, yet, just, for, since</strong> często pojawiają się z Present Perfect.",
        "Kluczowe pytanie: czy czas nadal łączy się z teraźniejszością, czy jest już całkowicie zakończony?"
    ]
}

